// NQxb_Artifact_Save_v1__Normalize_Request
// Canonicalize inbound save request with field presence tracking
// Phase 3 contract: PATCH semantics for UPDATE
// v1.2: Lifecycle alignment for project artifacts
// v1.3: instruction_pack DB invariant — ensure content.scope is set from extension.scope (tool-safe)
// v1.4: Convert empty string UUIDs to null (fixes Telegram empty parent_artifact_id)
// v1.5: BUG-011 fix - tags normalization
// v1.6: Split comma-separated strings
// v1.7: Dual-shape tolerant (Gateway + Internal Promote/Query callers)
// v1.8: Forward execution_status (Phase 2B Walk types)

const raw = $json ?? {};

const body =
  raw.body && typeof raw.body === "object" && !Array.isArray(raw.body)
    ? raw.body
    : null;

const req = body ?? raw;

const asObj = (v) =>
  v && typeof v === "object" && !Array.isArray(v) ? v : {};

const trimStr = (v) => (typeof v === "string" ? v.trim() : v);

// Convert empty strings to null for UUID fields
const uuidOrNull = (v) =>
  typeof v === "string" && v.trim() !== "" ? v.trim() : null;

// -------------------------
// Field Fallback Resolution
// -------------------------

const artifact_id =
  uuidOrNull(req.artifact_id) ??
  uuidOrNull(req.req_artifact_id) ??
  null;

const is_update = artifact_id !== null;

const artifact_type =
  (req.artifact_type ??
   req.req_artifact_type ??
   "").toString().trim();

const gw_workspace_id =
  req.gw_workspace_id ??
  req.workspace_id ??
  req.req_gw_workspace_id ??
  null;

const owner_user_id =
  req.owner_user_id ??
  req.actor_user_id ??
  null;

const title =
  req.title ??
  req.req_title ??
  null;

const parent_artifact_id =
  uuidOrNull(req.parent_artifact_id) ??
  uuidOrNull(req.req_parent_artifact_id) ??
  null;

// Track PATCH semantics (what caller explicitly provided)
const provided_fields = {
  title: "title" in req || "req_title" in req,
  summary: "summary" in req,
  priority: "priority" in req,
  lifecycle_status: "lifecycle_status" in req,
  tags: "tags" in req,
  content: "content" in req,
  parent_artifact_id:
    "parent_artifact_id" in req || "req_parent_artifact_id" in req,
  execution_status: "execution_status" in req,
};

// -------------------------
// Lifecycle Alignment
// -------------------------

let lifecycle_status = req.lifecycle_status ?? null;

if (artifact_type === "project" && !is_update) {
  const lifecycle_stage = req.extension?.lifecycle_stage;
  if (lifecycle_stage && !lifecycle_status) {
    lifecycle_status = lifecycle_stage;
  }
}

// -------------------------
// Tags Normalization (BUG-011)
// -------------------------

const normalizeTags = (v) => {
  let arr = [];

  if (Array.isArray(v)) {
    arr = v;
  } else if (v && typeof v === "object") {
    arr = Object.values(v);
  }

  const seen = new Set();

  return arr
    .flatMap(t => typeof t === "string" ? t.split(",") : [])
    .map(t => (typeof t === "string" ? t.trim().toLowerCase() : ""))
    .filter(t => t !== "" && !seen.has(t) && seen.add(t));
};

const normalized_tags = normalizeTags(req.tags);
const content_obj = asObj(req.content);
const extension_obj = asObj(req.extension);

// -------------------------
// Canonical Output
// -------------------------

const canonical = {
  gw_action: req.gw_action ?? "artifact.save",
  gw_workspace_id: gw_workspace_id,

  artifact_type: artifact_type,
  artifact_id: artifact_id,
  is_update: is_update,

  owner_user_id: owner_user_id,

  // Spine fields
  title: title,
  summary: req.summary ?? null,
  priority: req.priority ?? 3,
  lifecycle_status: lifecycle_status,
  tags: normalized_tags,
  content: content_obj,
  parent_artifact_id: parent_artifact_id,
  execution_status: req.execution_status ?? null,

  // Extension
  extension: extension_obj,

  // PATCH metadata
  _provided_fields: provided_fields,
};

// -------------------------
// instruction_pack invariant
// -------------------------

if (canonical.artifact_type === "instruction_pack") {
  const scope = (canonical.extension?.scope ?? "").toString().trim();
  if (scope) {
    if (
      !canonical.content ||
      typeof canonical.content !== "object" ||
      Array.isArray(canonical.content)
    ) {
      canonical.content = {};
    }
    canonical.content.scope = scope;
  }
}

// -------------------------
// Debug (minimal + stable)
// -------------------------

canonical._gw_debug = {
  received_shape: body ? "body" : "flat",
  operation: is_update ? "UPDATE" : "INSERT",
  lifecycle_aligned:
    artifact_type === "project" &&
    !is_update &&
    lifecycle_status !== req.lifecycle_status,
  dual_shape_tolerant: true,
};

return [{ json: canonical }];

// NQxb_Artifact_Save_v1__Validate_Request
// Comprehensive validation with consistent envelope + explicit ok flag for routing
// v2.0: Removed hardcoded validTypes array - now uses Type Registry Guard
// v2.1: Added instruction_pack INSERT validation (scope/active/priority/pack_format)
// v2.2: Added journal strict extension contract (entry_text only, no other keys)

const req = $json;
const errors = [];

// Helpers
const isNonEmptyString = (v) => typeof v === 'string' && v.trim() !== '';
const trimOrNull = (v) => (typeof v === 'string' ? v.trim() : v ?? null);

// Always required
if (!isNonEmptyString(req.gw_workspace_id)) {
  errors.push({ field: 'gw_workspace_id', reason: 'required' });
}

if (!isNonEmptyString(req.artifact_type)) {
  errors.push({ field: 'artifact_type', reason: 'required' });
}

const artifact_type = trimOrNull(req.artifact_type);
const is_update = req.is_update === true;

// NOTE: artifact_type allow-list validation REMOVED
// Type Registry Guard now handles this check downstream

// Operation-specific requirements
if (is_update) {
  // UPDATE requirements
  if (!isNonEmptyString(req.artifact_id)) {
    errors.push({ field: 'artifact_id', reason: 'required for UPDATE operation' });
  }

  // If title is provided for UPDATE, it must be non-empty
  if (req._provided_fields?.title && !isNonEmptyString(req.title)) {
    errors.push({ field: 'title', reason: 'if provided for UPDATE, must be non-empty' });
  }
} else {
  // INSERT requirements
  if (!isNonEmptyString(req.owner_user_id)) {
    errors.push({ field: 'owner_user_id', reason: 'required for INSERT operation' });
  }

  if (!isNonEmptyString(req.title)) {
    errors.push({ field: 'title', reason: 'required for INSERT operation' });
  }
}

// Type-specific validation
if (artifact_type === 'project') {
  if (!is_update) {
    if (!isNonEmptyString(req.extension?.lifecycle_stage)) {
      errors.push({ field: 'extension.lifecycle_stage', reason: 'required for project INSERT' });
    }
  }
} else if (artifact_type === 'restart' || artifact_type === 'snapshot') {
  if (!is_update) {
    if (
      !req.extension?.payload ||
      typeof req.extension.payload !== 'object' ||
      Array.isArray(req.extension.payload)
    ) {
      errors.push({
        field: 'extension.payload',
        reason: `required for ${artifact_type} INSERT (must be object)`,
      });
    }
  }
} else if (artifact_type === 'instruction_pack') {
  if (!is_update) {
    // Required extension metadata for instruction_pack INSERT (matches qxb_artifact_instruction_pack schema)
    if (!isNonEmptyString(req.extension?.scope)) {
      errors.push({ field: 'extension.scope', reason: 'required for instruction_pack INSERT' });
    }

    if (typeof req.extension?.active !== 'boolean') {
      errors.push({
        field: 'extension.active',
        reason: 'required for instruction_pack INSERT (boolean)',
      });
    }

    if (typeof req.extension?.priority !== 'number') {
      errors.push({
        field: 'extension.priority',
        reason: 'required for instruction_pack INSERT (number)',
      });
    }

    if (!isNonEmptyString(req.extension?.pack_format)) {
      errors.push({
        field: 'extension.pack_format',
        reason: 'required for instruction_pack INSERT',
      });
    }
  }
} else if (artifact_type === 'journal') {
  if (!is_update) {
    // Strict journal extension contract (v2.2):
    // - extension.entry_text required (non-empty string)
    // - No other extension keys permitted
    // - payload column intentionally deprecated for journal saves
    const ext = req.extension;
    const journalErrors = [];

    if (!ext || typeof ext !== 'object' || Array.isArray(ext)) {
      journalErrors.push('extension must exist and be an object');
    } else {
      if (typeof ext.entry_text !== 'string' || ext.entry_text.trim().length === 0) {
        journalErrors.push('extension.entry_text must be a non-empty string');
      }
      const allowedKeys = ['entry_text'];
      const extraKeys = Object.keys(ext).filter(k => !allowedKeys.includes(k));
      if (extraKeys.length > 0) {
        journalErrors.push('unknown extension keys: ' + extraKeys.join(', '));
      }
    }

    if (journalErrors.length > 0) {
      return [{
        json: {
          ok: false,
          _gw_route: 'error',
          gw_action: req.gw_action ?? null,
          gw_workspace_id: req.gw_workspace_id ?? null,
          artifact_type: artifact_type ?? null,
          artifact_id: req.artifact_id ?? null,
          is_update,
          error: {
            code: 'JOURNAL_EXTENSION_INVALID',
            message: 'Journal artifacts require extension.entry_text (non-empty string). No other extension fields are permitted.',
            details: {
              validation_errors: journalErrors,
              artifact_type: 'journal',
              operation: 'INSERT',
            },
          },
        },
      }];
    }
  }
}

// If validation failed, return standardized error envelope
if (errors.length > 0) {
  return [
    {
      json: {
        ok: false,
        _gw_route: 'error',
        gw_action: req.gw_action ?? null,
        gw_workspace_id: req.gw_workspace_id ?? null,
        artifact_type: artifact_type ?? null,
        artifact_id: req.artifact_id ?? null,
        is_update,
        error: {
          code: 'VALIDATION_ERROR',
          message: `Validation failed for artifact.save operation (${is_update ? 'UPDATE' : 'INSERT'})`,
          details: {
            validation_errors: errors,
            artifact_type: artifact_type ?? null,
            operation: is_update ? 'UPDATE' : 'INSERT',
          },
        },
      },
    },
  ];
}

// Valid — return explicit ok=true + pass-through request for downstream steps
return [
  {
    json: {
      ok: true,
      _gw_route: 'ok',
      ...req,
    },
  },
];

// NQxb_Artifact_Save_v1__Normalize_Saved_ID
// Purpose: Extract artifact_id from Supabase INSERT response AND carry forward
// key request fields needed by downstream nodes (like lifecycle_stage).

const raw = $json ?? {};

// Pull request (canonical) from Normalize_Request node so we don't lose context
const req = $node["NQxb_Artifact_Save_v1__Normalize_Request"]?.json ?? {};

// Try multiple possible locations for artifact_id in Supabase responses
const saved_artifact_id =
  raw.artifact_id ||
  raw.id ||
  raw.data?.[0]?.artifact_id ||
  raw.data?.[0]?.id ||
  null;

if (!saved_artifact_id) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "SAVE_ID_MISSING",
          message: "Could not extract saved artifact_id from Supabase INSERT response",
          details: {
            keys_present: Object.keys(raw),
          },
        },
      },
    },
  ];
}

// Output: keep insert response, AND carry forward lifecycle fields for downstream use
return [
  {
    json: {
      saved_artifact_id,
      lifecycle_stage: req.extension?.lifecycle_stage ?? null,
      operational_status: req.extension?.operational_state?.status ?? "active",
      state_reason: req.extension?.state_reason ?? null,
      _insert_response: raw,
    },
  },
];

// Check immutability for UPDATE operations
// Return error envelope instead of throwing

const artifact_type = ($node['NQxb_Artifact_Save_v1__Normalize_Request'].json.artifact_type ?? '').trim();

if (artifact_type === 'restart' || artifact_type === 'snapshot') {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "IMMUTABILITY_ERROR",
          message: `Artifact type '${artifact_type}' is immutable and cannot be updated. Only INSERT operations are allowed.`,
          details: {
            artifact_type: artifact_type,
            artifact_id: $json.artifact_id,
            operation_attempted: 'UPDATE',
          },
        },
      },
    },
  ];
}

// Pass through if mutable type
return [$input.item];

// Check if artifact exists, return NOT_FOUND if not
// Implement PATCH semantics: merge request with existing values
// v1.1: Fix Supabase get() array handling

const normalizeNode =
  $node['NQxb_Artifact_Save_v1__Normalize_Request'].json;

// Supabase get() returns array — normalize to single row
const existingRaw = $json;
const existing = Array.isArray(existingRaw)
  ? existingRaw[0]
  : existingRaw;

// Check if artifact was found
if (!existing || !existing.artifact_id) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "NOT_FOUND",
          message: "Artifact not found for UPDATE operation",
          details: {
            artifact_id: normalizeNode.artifact_id,
            workspace_id: normalizeNode.gw_workspace_id,
            operation: "UPDATE",
          },
        },
      },
    },
  ];
}

// PATCH semantics: merge provided fields with existing
const provided = normalizeNode._provided_fields || {};

const merged = {
  artifact_id: existing.artifact_id,
  workspace_id: existing.workspace_id,
  artifact_type: existing.artifact_type,
  owner_user_id: existing.owner_user_id,

  // PATCH: only update if explicitly provided
  title: provided.title ? normalizeNode.title : existing.title,
  summary: provided.summary ? normalizeNode.summary : existing.summary,
  priority: provided.priority ? normalizeNode.priority : existing.priority,
  lifecycle_status: provided.lifecycle_status
    ? normalizeNode.lifecycle_status
    : existing.lifecycle_status,
  tags: provided.tags ? normalizeNode.tags : existing.tags,
  content: provided.content ? normalizeNode.content : existing.content,
  parent_artifact_id: provided.parent_artifact_id
    ? normalizeNode.parent_artifact_id
    : existing.parent_artifact_id,
  execution_status: provided.execution_status
    ? normalizeNode.execution_status
    : existing.execution_status,

  // Pass through normalized request for downstream nodes
  _normalized_request: normalizeNode,
  _existing_artifact: existing,
};

return [{ json: merged }];

// PATCH semantics for project extension

const existing = $json;
const normalizeNode = $node['NQxb_Artifact_Save_v1__Normalize_Request'].json;
const extension = normalizeNode.extension || {};

// Merge: only update fields that were explicitly provided in extension
const hasLifecycleStage = 'lifecycle_stage' in extension;
const hasOperationalState = 'operational_state' in extension;
const hasStateReason = 'state_reason' in extension;

const merged = {
  artifact_id: normalizeNode.artifact_id,
  lifecycle_stage: hasLifecycleStage ? extension.lifecycle_stage : (existing?.lifecycle_stage || null),
  operational_state: hasOperationalState ? extension.operational_state : (existing?.operational_state || 'active'),
  state_reason: hasStateReason ? extension.state_reason : (existing?.state_reason || null),
};

return [{ json: merged }];

// Create missing project extension row with defaults
// Requirement #4: UPSERT behavior for UPDATE operations

const normalizeNode = $node['NQxb_Artifact_Save_v1__Normalize_Request'].json;
const extension = normalizeNode.extension || {};

// Use provided values or defaults
const merged = {
  artifact_id: normalizeNode.artifact_id,
  lifecycle_stage: extension.lifecycle_stage || 'seed',
  operational_state: extension.operational_state || 'active',
  state_reason: extension.state_reason || null,
};

return [{ json: merged }];

// PATCH semantics for journal extension

const existing = $json;
const normalizeNode = $node['NQxb_Artifact_Save_v1__Normalize_Request'].json;
const extension = normalizeNode.extension || {};

const hasEntryText = 'entry_text' in extension;
const hasPayload = 'payload' in extension;

const merged = {
  artifact_id: normalizeNode.artifact_id,
  entry_text: hasEntryText ? extension.entry_text : (existing?.entry_text || null),
  payload: hasPayload ? extension.payload : (existing?.payload || null),
};

return [{ json: merged }];

// Create missing journal extension row with defaults
// Requirement #4: UPSERT behavior for UPDATE operations

const normalizeNode = $node['NQxb_Artifact_Save_v1__Normalize_Request'].json;
const extension = normalizeNode.extension || {};

const merged = {
  artifact_id: normalizeNode.artifact_id,
  entry_text: extension.entry_text || null,
  payload: extension.payload || null,
};

return [{ json: merged }];

// NQxb_Artifact_Save_v1__Return_Response
// FIX: fail-closed, never ok:true without a real artifact_id
// FIX: preserve upstream error envelopes
// FIX: map Supabase unique-violation (23505 / 409 / duplicate key) => CONFLICT (allow-listed)
// FIX: handle "ok:true but error:string" (common with Supabase node + continueErrorOutput)
// FIX: map IMMUTABILITY_ERROR => IMMUTABLE_RECORD (allow-listed)
// NOTE: Error codes MUST come from locked allow-list (Phase 3 contract)

const j = $json ?? {};
const now = new Date().toISOString();

// Locked allow-list (Phase 3 contract)
const ALLOWED_ERROR_CODES = new Set([
  'AUTH_REQUIRED',
  'WORKSPACE_FORBIDDEN',
  'ARTIFACT_TYPE_NOT_ALLOWED',
  'ACTION_NOT_ALLOWED',
  'VALIDATION_ERROR',
  'NOT_FOUND',
  'CONFLICT',
  'IMMUTABLE_RECORD',
  'LIFECYCLE_TRANSITION_NOT_ALLOWED',
  'SNAPSHOT_REQUIRED',
  'JOURNAL_EXTENSION_INVALID',
  'INTERNAL_ERROR',
]);

// Helpers
const safeStr = (v) => (typeof v === 'string' ? v : v == null ? null : String(v));
const coalesce = (...vals) => {
  for (const v of vals) if (v !== undefined && v !== null) return v;
  return null;
};

const isUniqueViolationText = (s) => {
  const txt = (s ?? '').toString();
  return (
    txt.includes('"code":"23505"') ||
    txt.includes('23505') ||
    txt.toLowerCase().includes('duplicate key value violates unique constraint') ||
    txt.toLowerCase().includes('violates unique constraint') ||
    txt.toLowerCase().includes('unique constraint')
  );
};

const ctxNormalize = (() => {
  try {
    return $node['NQxb_Artifact_Save_v1__Normalize_Request']?.json ?? {};
  } catch (e) {
    return {};
  }
})();

const gw_action = coalesce(j.gw_action, ctxNormalize.gw_action, 'artifact.save');

// Workspace id may appear as gw_workspace_id or workspace_id depending on stage
const workspace_id = coalesce(
  j.gw_workspace_id,
  j.workspace_id,
  ctxNormalize.gw_workspace_id,
  ctxNormalize.workspace_id
);

const artifact_type = coalesce(j.saved_artifact_type, j.artifact_type, ctxNormalize.artifact_type);

// ---- helper: build a proper error envelope with allow-list enforcement
const buildErrorEnvelope = ({ code, message, details, artifact_id = null }) => {
  // Map known non-allowlisted internal codes into allowlist
  let mapped = code;
  if (mapped === 'IMMUTABILITY_ERROR') mapped = 'IMMUTABLE_RECORD';

  const finalCode = ALLOWED_ERROR_CODES.has(mapped) ? mapped : 'INTERNAL_ERROR';

  return [
    {
      json: {
        ok: false,
        _gw_route: 'error',
        gw_action,
        gw_workspace_id: workspace_id,
        artifact_type,
        artifact_id,
        error: {
          code: finalCode,
          message: safeStr(message) ?? 'Gateway error',
          details:
            finalCode === mapped
              ? (details ?? {})
              : {
                  original: { code, message, details },
                  note: 'Error code not allow-listed; mapped to INTERNAL_ERROR',
                },
        },
        timestamp: now,
      },
    },
  ];
};

// 1) If upstream already produced an error envelope, preserve it (but enforce allow-list)
if (j && (j.ok === false || j._gw_route === 'error')) {
  const upstreamErr = j.error ?? {};
  const upstreamCodeRaw = safeStr(upstreamErr.code);

  // Special: map immutability into allowlist code
  const upstreamCode =
    upstreamCodeRaw === 'IMMUTABILITY_ERROR' ? 'IMMUTABLE_RECORD' : upstreamCodeRaw;

  const code = ALLOWED_ERROR_CODES.has(upstreamCode) ? upstreamCode : 'INTERNAL_ERROR';
  const message = safeStr(upstreamErr.message) ?? 'Gateway error';
  const details = upstreamErr.details ?? {};

  return [
    {
      json: {
        ...j,
        ok: false,
        _gw_route: 'error',
        gw_action,
        gw_workspace_id: workspace_id,
        artifact_type,
        error: {
          code,
          message,
          details: ALLOWED_ERROR_CODES.has(upstreamCode)
            ? details
            : {
                original_error: upstreamErr,
                note: 'Upstream error code was not allow-listed; mapped to INTERNAL_ERROR',
              },
        },
        timestamp: now,
      },
    },
  ];
}

// 2) n8n failure object (Continue On Fail output)
if (j && (j.errorMessage || j.errorDescription || j.errorDetails || j.n8nDetails)) {
  const httpCodeRaw = j.errorDetails?.httpCode;
  const httpCode = Number(httpCodeRaw ?? NaN);

  const raw = Array.isArray(j.errorDetails?.rawErrorMessage)
    ? j.errorDetails.rawErrorMessage.join(' ')
    : safeStr(j.errorDetails?.rawErrorMessage) ?? '';

  const isUnique = (httpCode === 409) || isUniqueViolationText(raw);

  const code = isUnique ? 'CONFLICT' : 'INTERNAL_ERROR';
  const message = safeStr(j.errorDescription) ?? safeStr(j.errorMessage) ?? 'Request failed';

  return buildErrorEnvelope({
    code,
    message,
    details: {
      httpCode: Number.isFinite(httpCode) ? httpCode : null,
      rawErrorMessage: j.errorDetails?.rawErrorMessage ?? null,
      n8nDetails: j.n8nDetails ?? null,
    },
  });
}

// 2a) IMPORTANT: Supabase node + continueErrorOutput often yields:
// ok:true, _gw_route:'ok', artifact_id:null, error:'duplicate key value ...'
if (typeof j.error === 'string' && j.error.trim() !== '') {
  const errText = j.error.trim();
  const code = isUniqueViolationText(errText) ? 'CONFLICT' : 'INTERNAL_ERROR';

  return buildErrorEnvelope({
    code,
    message: isUniqueViolationText(errText)
      ? 'Conflict: unique constraint violation'
      : 'Upstream database error',
    details: {
      rawErrorMessage: errText,
      note: 'Received ok:true with error:string (likely Supabase node error output)',
    },
  });
}

// 3) Normal success response
const isUpdate = j.is_update === true;
const op = isUpdate ? 'UPDATE' : 'INSERT';

const artifact_id = coalesce(j.saved_artifact_id, j.artifact_id);
const extension = j.extension ?? null;

// FAIL-CLOSED: no artifact_id => INTERNAL_ERROR
if (!artifact_id) {
  return buildErrorEnvelope({
    code: 'INTERNAL_ERROR',
    message: 'artifact.save completed response stage without a valid artifact_id (fail-closed)',
    details: {
      operation: op,
      note: 'Upstream insert/update did not yield an artifact_id; refusing to return ok:true',
      keys_present: Object.keys(j ?? {}),
    },
  });
}

return [
  {
    json: {
      ok: true,
      gw_action,
      artifact_id,
      artifact_type,
      workspace_id,
      operation: op,
      extension,
      _owner_source: j._owner_source ?? null,
      timestamp: now,
    },
  },
];

// NQxb_Artifact_Save_v1__Freeze_Extension_Payload
// Freeze extension.payload early so later DB nodes cannot wipe it.

const payload =
  $json?.extension && typeof $json.extension === "object" && !Array.isArray($json.extension)
    ? ($json.extension.payload ?? {})
    : {};

return [
  {
    json: {
      ...($json ?? {}),
      _frozen_extension_payload: payload,
    },
  },
];

// NQxb_Artifact_Save_v1__Derive_Owner_From_Auth
// Derive owner_user_id from authenticated principal (Basic Auth username).
// Ignore caller-supplied owner_user_id for INSERT safety.

const j = $json ?? {};

// If already present (e.g., internal calls), keep it.
// But for external callers, we will overwrite based on auth when possible.
const authUser =
  j._gw_debug?.auth_username ??
  j._gw_debug?.basic_username ??
  null;

if (!authUser) {
  // No auth principal available -> cannot derive owner.
  // Leave owner_user_id untouched and let validation fail with a clear reason.
  j._owner_source = "missing_auth_username";
  return [{ json: j }];
}

// MVP mapping: Basic Auth user -> qxb_user.user_id (known-good)
if (authUser === "qwrk-gateway") {
  j.owner_user_id = "c52c7a57-74ad-433d-a07c-4dcac1778672";
  j._owner_source = "auth_username_map";
  return [{ json: j }];
